using System.Net;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// Breaking change 1: .NET 9 enables ValidateScopes in development by default.
// A Singleton capturing a Scoped dependency now throws at startup.
// Fix: match the lifetime — register as Scoped instead of Singleton.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// Breaking change 2: .NET 9 HttpClientFactory defaults to SocketsHttpHandler.
// The previous cast to HttpClientHandler throws InvalidCastException at runtime.
// Fix: configure the primary handler directly with SocketsHttpHandler.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// Breaking change 3: .NET 9 redacts all header values in Trace-level HttpClientFactory logs.
// Fix: allowlist specific non-sensitive headers needed for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(name =>
        name != "X-Request-Id" &&
        name != "Cache-Control" &&
        name != "Content-Type" &&
        name != "Accept"));

builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // Breaking change 4: .NET 9 ignores X-Forwarded-* from proxies not in
    // KnownProxies/KnownNetworks. Fix: register your trusted reverse proxy address(es).
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1")); // TODO: replace with actual proxy IP
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

